import hashlib
import os
def hash_file(path):
    h = hashlib.sha256()
    with open(path, 'rb') as f:
        for chunk in iter(lambda: f.read(8192), b''):
            h.update(chunk)
    return h.hexdigest()
results = []
for root, dirs, files in os.walk('{path}'):
    for filename in files:
        filepath = os.path.join(root, filename)
        file_hash = hash_file(filepath)
        results.append((filepath, file_hash))
        print(f'{file_hash[:16]}... {filepath}')
print(f'\nHashed {len(results)} files')

find_duplicate_files:
import hashlib
import os
from collections import defaultdict
def hash_file(path):
    h = hashlib.sha256()
    with open(path, 'rb') as f:
        for chunk in iter(lambda: f.read(8192), b''):
            h.update(chunk)
    return h.hexdigest()
hash_map = defaultdict(list)
for root, dirs, files in os.walk('{path}'):
    for filename in files:
        filepath = os.path.join(root, filename)
        file_hash = hash_file(filepath)
        hash_map[file_hash].append(filepath)
duplicates = {h: paths for h, paths in hash_map.items() if len(paths) > 1}
for hash_val, paths in duplicates.items():
    print(f'\nDuplicate group ({hash_val[:16]}...):')
    for p in paths:
        print(f'  {p}')
print(f'\nFound {len(duplicates)} groups of duplicate files')

list_files_by_size:
import os
files = []
for root, dirs, filenames in os.walk('{path}'):
    for filename in filenames:
        filepath = os.path.join(root, filename)
        size = os.path.getsize(filepath)
        files.append((filepath, size))
files.sort(key=lambda x: x[1], reverse=True)
for filepath, size in files[:20]:
    if size > 1024*1024:
        print(f'{size/1024/1024:.1f} MB  {filepath}')
    elif size > 1024:
        print(f'{size/1024:.1f} KB  {filepath}')
    else:
        print(f'{size} B   {filepath}')
print(f'\nTotal: {len(files)} files, {sum(s for _, s in files):,} bytes')

list_files_by_type:
import os
from collections import Counter
ext_counter = Counter()
for root, dirs, files in os.walk('{path}'):
    for filename in files:
        ext = os.path.splitext(filename)[1].lower() or '(no ext)'
        ext_counter[ext] += 1
for ext, count in ext_counter.most_common():
    print(f'{ext}: {count} files')
print(f'\nTotal: {sum(ext_counter.values())} files, {len(ext_counter)} types')

