import os
import time
import hashlib
def hash_file(path):
    h = hashlib.md5()
    with open(path, 'rb') as f:
        h.update(f.read())
    return h.hexdigest()
path = '{path}'
state = {}
for root, dirs, files in os.walk(path):
    for filename in files:
        filepath = os.path.join(root, filename)
        state[filepath] = hash_file(filepath)
print(f'Monitoring {len(state)} files in {path}...')
while True:
    time.sleep(2)
    for filepath, old_hash in list(state.items()):
        if os.path.exists(filepath):
            new_hash = hash_file(filepath)
            if new_hash != old_hash:
                print(f'CHANGED: {filepath}')
                state[filepath] = new_hash
        else:
            print(f'DELETED: {filepath}')
            del state[filepath]

