import json
import os
db_file = '{json_path}'
if os.path.exists(db_file):
    with open(db_file, 'r') as f:
        store = json.load(f)
else:
    store = {}
def kv_set(key, value):
    store[key] = value
    with open(db_file, 'w') as f:
        json.dump(store, f, indent=2)
    print(f'SET {key} = {value}')
def kv_get(key):
    val = store.get(key, None)
    print(f'GET {key} = {val}')
    return val
def kv_delete(key):
    if key in store:
        del store[key]
        with open(db_file, 'w') as f:
            json.dump(store, f, indent=2)
        print(f'DEL {key}')
def kv_list():
    for k, v in store.items():
        print(f'{k}: {v}')
kv_set('name', 'test')
kv_set('version', '1.0')
kv_get('name')
kv_list()
